133	// PagesFactory somehow creates some Pages.
134	// We do a lot of lazy Pages initialization in Hugo, so we need a type.
135	type PagesFactory func() Pages
136	
137	var (
138		_ resource.ResourcesConverter = Pages{}
139		_ compare.ProbablyEqer        = Pages{}
140	)
