124	// page returns the Page with the given index
125	func (p *Pager) page(index int) (Page, error) {
126		if pages, ok := p.element().(Pages); ok {
127			if pages != nil && len(pages) > index {
128				return pages[index], nil
129			}
130			return nil, nil
131		}
132	
133		// must be PagesGroup
134		// this construction looks clumsy, but ...
135		// ... it is the difference between 99.5% and 100% test coverage :-)
136		groups := p.element().(PagesGroup)
137	
138		i := 0
139		for _, v := range groups {
140			for _, page := range v.Pages {
141				if i == index {
142					return page, nil
143				}
144				i++
145			}
146		}
147		return nil, nil
148	}
