211	func splitPages(pages Pages, size int) []paginatedElement {
212		var split []paginatedElement
213		for low, j := 0, len(pages); low < j; low += size {
214			high := int(math.Min(float64(low+size), float64(len(pages))))
215			split = append(split, pages[low:high])
216		}
217	
218		return split
219	}
220	
221	func splitPageGroups(pageGroups PagesGroup, size int) []paginatedElement {
222		type keyPage struct {
223			key  any
224			page Page
225		}
226	
227		var (
228			split     []paginatedElement
229			flattened []keyPage
230		)
231	
232		for _, g := range pageGroups {
233			for _, p := range g.Pages {
234				flattened = append(flattened, keyPage{g.Key, p})
235			}
236		}
237	
238		numPages := len(flattened)
239	
240		for low, j := 0, numPages; low < j; low += size {
241			high := int(math.Min(float64(low+size), float64(numPages)))
242	
243			var (
244				pg         PagesGroup
245				key        any
246				groupIndex = -1
247			)
248	
249			for k := low; k < high; k++ {
250				kp := flattened[k]
251				if key == nil || key != kp.key {
252					key = kp.key
253					pg = append(pg, PageGroup{Key: key})
254					groupIndex++
255				}
256				pg[groupIndex].Pages = append(pg[groupIndex].Pages, kp.page)
257			}
258			split = append(split, pg)
259		}
260	
261		return split
262	}
263	
264	func ResolvePagerSize(conf config.AllProvider, options ...any) (int, error) {
265		if len(options) == 0 {
266			return conf.Pagination().PagerSize, nil
267		}
268	
269		if len(options) > 1 {
270			return -1, errors.New("too many arguments, 'pager size' is currently the only option")
271		}
272	
273		pas, err := cast.ToIntE(options[0])
274	
275		if err != nil || pas <= 0 {
276			return -1, errors.New(("'pager size' must be a positive integer"))
277		}
278	
279		return pas, nil
280	}
281	
282	func Paginate(td TargetPathDescriptor, seq any, pagerSize int) (*Paginator, error) {
283		if pagerSize <= 0 {
284			return nil, errors.New("'paginate' configuration setting must be positive to paginate")
285		}
286	
287		urlFactory := newPaginationURLFactory(td)
288	
289		var paginator *Paginator
290	
291		groups, ok, err := ToPagesGroup(seq)
292		if err != nil {
293			return nil, err
294		}
295		if ok {
296			paginator, _ = newPaginatorFromPageGroups(groups, pagerSize, urlFactory)
297		} else {
298			pages, err := ToPages(seq)
299			if err != nil {
300				return nil, err
301			}
302			paginator, _ = newPaginatorFromPages(pages, pagerSize, urlFactory)
303		}
304	
305		return paginator, nil
306	}
307	
308	// probablyEqual checks page lists for probable equality.
309	// It may return false positives.
310	// The motivation behind this is to avoid potential costly reflect.DeepEqual
311	// when "probably" is good enough.
312	func probablyEqualPageLists(a1 any, a2 any) bool {
313		if a1 == nil || a2 == nil {
314			return a1 == a2
315		}
316	
317		t1 := reflect.TypeOf(a1)
318		t2 := reflect.TypeOf(a2)
319	
320		if t1 != t2 {
321			return false
322		}
323	
324		if g1, ok := a1.(PagesGroup); ok {
325			g2 := a2.(PagesGroup)
326			if len(g1) != len(g2) {
327				return false
328			}
329			if len(g1) == 0 {
330				return true
331			}
332			if g1.Len() != g2.Len() {
333				return false
334			}
335	
336			return g1[0].Pages[0] == g2[0].Pages[0]
337		}
338	
339		p1, err1 := ToPages(a1)
340		p2, err2 := ToPages(a2)
341	
342		// probably the same wrong type
343		if err1 != nil && err2 != nil {
344			return true
345		}
346	
347		if len(p1) != len(p2) {
348			return false
349		}
350	
351		if len(p1) == 0 {
352			return true
353		}
354	
355		return p1[0] == p2[0]
356	}
357	
358	func newPaginatorFromPages(pages Pages, size int, urlFactory paginationURLFactory) (*Paginator, error) {
359		if size <= 0 {
360			return nil, errors.New("Paginator size must be positive")
361		}
362	
363		split := splitPages(pages, size)
364	
365		return newPaginator(split, len(pages), size, urlFactory)
366	}
367	
368	func newPaginatorFromPageGroups(pageGroups PagesGroup, size int, urlFactory paginationURLFactory) (*Paginator, error) {
369		if size <= 0 {
370			return nil, errors.New("Paginator size must be positive")
371		}
372	
373		split := splitPageGroups(pageGroups, size)
374	
375		return newPaginator(split, pageGroups.Len(), size, urlFactory)
376	}
377	
378	func newPaginator(elements []paginatedElement, total, size int, urlFactory paginationURLFactory) (*Paginator, error) {
379		p := &Paginator{total: total, paginatedElements: elements, size: size, paginationURLFactory: urlFactory}
380	
381		var ps pagers
382	
383		if len(elements) > 0 {
384			ps = make(pagers, len(elements))
385			for i := range p.paginatedElements {
386				ps[i] = &Pager{number: (i + 1), Paginator: p}
387			}
388		} else {
389			ps = make(pagers, 1)
390			ps[0] = &Pager{number: 1, Paginator: p}
391		}
392	
393		p.pagers = ps
394	
395		return p, nil
396	}
397	
398	func newPaginationURLFactory(d TargetPathDescriptor) paginationURLFactory {
399		return func(pageNumber int) string {
400			pathDescriptor := d
401			var rel string
402			if pageNumber > 1 {
403				rel = fmt.Sprintf("/%s/%d/", d.PathSpec.Cfg.Pagination().Path, pageNumber)
404				pathDescriptor.Addends = rel
405			}
406	
407			return CreateTargetPaths(pathDescriptor).RelPermalink(d.PathSpec)
408		}
409	}
