404	func (h *HugoSites) reportProgress(f func() (state terminal.ProgressState, progress float64)) {
405		h.progressReporter.mu.Lock()
406		defer h.progressReporter.mu.Unlock()
407	
408		if h.progressReporter.t.IsZero() {
409			// Not started yet, queue it up and return.
410			h.progressReporter.queue = append(h.progressReporter.queue, f)
411			return
412		}
413	
414		handleOne := func(skip func(state terminal.ProgressState, progress float64) bool, handle func() (state terminal.ProgressState, progress float64)) {
415			state, progress := handle()
416			if skip != nil && skip(state, progress) {
417				return
418			}
419	
420			if h.progressReporter.progress > 0 && h.progressReporter.state == state && progress <= h.progressReporter.progress {
421				// Only report progress forward.
422				return
423			}
424	
425			h.progressReporter.state = state
426			h.progressReporter.progress = progress
427			terminal.ReportProgress(h.Log.StdOut(), state, h.progressReporter.progress)
428		}
429	
430		// Drain queue first.
431		skip := func(state terminal.ProgressState, progress float64) bool {
432			// Skip qued up intermediate states if we already are in normal state.
433			return h.progressReporter.state == terminal.ProgressNormal && state == terminal.ProgressIntermediate
434		}
435		for _, ff := range h.progressReporter.queue {
436			handleOne(skip, ff)
437		}
438		h.progressReporter.queue = nil
439	
440		handleOne(nil, f)
441	}
