611		// Use this to indicate what changed (for rebuilds).
612		WhatChanged *WhatChanged
613	
614		// This is a partial re-render of some selected pages.
615		PartialReRender bool
616	
617		// Set in server mode when the last build failed for some reason.
618		ErrRecovery bool
619	
620		// Recently visited or touched URLs. This is used for partial re-rendering.
621		RecentlyTouched *types.EvictingQueue[string]
622	
623		// Can be set to build only with a sub set of the content source.
624		ContentInclusionFilter *hglob.FilenameFilter
