807	func (h *HugoSites) readData(f *source.File) (any, error) {
808		file, err := f.FileInfo().Meta().Open()
809		if err != nil {
810			return nil, fmt.Errorf("readData: failed to open data file: %w", err)
811		}
812		defer file.Close()
813		content := helpers.ReaderToBytes(file)
814	
815		format := metadecoders.FormatFromString(f.Ext())
816		return metadecoders.Default.Unmarshal(content, format)
817	}
