72	func (t *templateNamespace) doParseTemplate(ti *TemplInfo) error {
73		if !ti.noBaseOf || ti.category == CategoryBaseof {
74			// Delay parsing until we have the base template.
75			return nil
76		}
77		pi := ti.PathInfo
78		name := pi.PathNoLeadingSlash()
79	
80		var (
81			templ tpl.Template
82			err   error
83		)
84	
85		if ti.D.IsPlainText {
86			prototype := t.parseText
87			if prototype.Lookup(name) != nil {
88				name += "-" + strconv.FormatUint(t.nameCounter.Add(1), 10)
89			}
90			templ, err = prototype.New(name).Parse(ti.content)
91			if err != nil {
92				return err
93			}
94		} else {
95			prototype := t.parseHTML
96			if prototype.Lookup(name) != nil {
97				name += "-" + strconv.FormatUint(t.nameCounter.Add(1), 10)
98			}
99			templ, err = prototype.New(name).Parse(ti.content)
100			if err != nil {
101				return err
102			}
103	
104			if ti.subCategory == SubCategoryEmbedded {
105				// In Hugo 0.146.0 we moved the internal templates around.
106				// For the "_internal/twitter_cards.html" style templates, they
107				// were moved to the _partials directory.
108				// But we need to make them accessible from the old path for a while.
109				if pi.Type() == paths.TypePartial {
110					aliasName := strings.TrimPrefix(name, "_partials/")
111					aliasName = "_internal/" + aliasName
112					_, err = prototype.AddParseTree(aliasName, templ.(*htmltemplate.Template).Tree)
113					if err != nil {
114						return err
115					}
116				}
117	
118				// This was also possible before Hugo 0.146.0, but this should be deprecated.
119				if pi.Type() == paths.TypeShortcode {
120					aliasName := strings.TrimPrefix(name, "_shortcodes/")
121					aliasName = "_internal/shortcodes/" + aliasName
122					_, err = prototype.AddParseTree(aliasName, templ.(*htmltemplate.Template).Tree)
123					if err != nil {
124						return err
125					}
126				}
127			}
128	
129			// Issue #13599.
130			if ti.category == CategoryPartial && ti.Fi != nil && ti.Fi.Meta().PathInfo.Section() == "partials" {
131				aliasName := strings.TrimPrefix(name, "_")
132				if _, err := prototype.AddParseTree(aliasName, templ.(*htmltemplate.Template).Tree); err != nil {
133					return err
134				}
135			}
136		}
137	
138		ti.Template = templ
139	
140		return nil
141	}
