262	func removeLeadingBOM(s string) string {
263		const bom = '\ufeff'
264	
265		for i, r := range s {
266			if i == 0 && r != bom {
267				return s
268			}
269			if i > 0 {
270				return s[i:]
271			}
272		}
273	
274		return s
275	}
