721	func (ps *pageState) renderResources() error {
722		for _, r := range ps.Resources() {
723			if _, ok := r.(page.Page); ok {
724				if !ps.s.h.BuildState.IsRebuild() {
725					// Pages gets rendered with the owning page but we count them here.
726					ps.s.PathSpec.ProcessingStats.Incr(&ps.s.PathSpec.ProcessingStats.Pages)
727				}
728				continue
729			}
730	
731			if resources.IsPublished(r) {
732				continue
733			}
734	
735			src, ok := r.(resource.Source)
736			if !ok {
737				return fmt.Errorf("resource %T does not support resource.Source", r)
738			}
739	
740			if err := src.Publish(); err != nil {
741				if !herrors.IsNotExist(err) {
742					ps.s.Log.Errorf("Failed to publish Resource for page %q: %s", ps.pathOrTitle(), err)
743				}
744			} else {
745				ps.s.PathSpec.ProcessingStats.Incr(&ps.s.PathSpec.ProcessingStats.Files)
746			}
747		}
748	
749		return nil
750	}
