752	func (ps *pageState) AlternativeOutputFormats() page.OutputFormats {
753		f := ps.outputFormat()
754		var o page.OutputFormats
755		for _, of := range ps.OutputFormats() {
756			if of.Format.NotAlternative || of.Format.Name == f.Name {
757				continue
758			}
759	
760			o = append(o, of)
761		}
762		return o
