801	func (ps *pageState) getContentConverter() converter.Converter {
802		var err error
803		ps.contentConverterInit.Do(func() {
804			if ps.m.pageConfigSource.ContentMediaType.IsZero() {
805				panic("ContentMediaType not set")
806			}
807			markup := ps.m.pageConfigSource.ContentMediaType.SubType
808	
809			if markup == "html" {
810				// Only reachable for shortcode inner content rendering; file-based
811				// HTML pages are gated at initFrontMatter via security.allowContent.
812				markup = "markdown"
813			}
814			ps.contentConverter, err = ps.m.newContentConverter(ps, markup)
815		})
816	
817		if err != nil {
818			ps.s.Log.Errorln("Failed to create content converter:", err)
819		}
820		return ps.contentConverter
821	}
